import{_ as e,c as a,o as i,a3 as s}from"./chunks/framework.DqsPtFs4.js";const p="/assets/image-1.DFgg5nQr.png",c="/assets/image-2.B9EhWlyD.png",n="/assets/image-3.DZmts5gU.png",A=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"network/http/accept.md","filePath":"network/http/accept.md","lastUpdated":1732620682000}'),l={name:"network/http/accept.md"};function r(h,t,o,d,g,u){return i(),a("div",null,t[0]||(t[0]=[s('<h2 id="内容协商" tabindex="-1">内容协商 <a class="header-anchor" href="#内容协商" aria-label="Permalink to &quot;内容协商&quot;">​</a></h2><p>在 HTTP 协议中，内容协商是一种机制，用于为同一 URI 提供资源不同的表示形式，以帮助用户代理指定最适合用户的表示形式（例如，哪种文档语言、哪种图片格式或者哪种内容编码）。</p><p>一份特定的文件被称为一项资源。当客户端获取资源的时候，会使用其对应的 URL 发送请求。服务器通过这个 URL 来选择它指向的资源的某一可用的变体——每一个变体称为一种表示形式——然后将这个选定的表示形式返回给客户端。整个资源，以及它的各种表示形式，共享一个特定的 URL。当访问某项资源的时候，内容协商会决定如何选择一种指定的表示形式。客户端和服务器端之间存在多种协商方式。最佳表示形式的选取可以通过两种机制实现：</p><ul><li>客户端设置特定的 HTTP 标头（又称为服务端驱动型内容协商或者主动内容协商），这是进行内容协商的标准方式。</li><li>服务器返回 300（Multiple Choices）或者 406（Not Acceptable）、415（Unsupported Media Type）HTTP 响应状态码 （又称为代理驱动型协商或者响应式协商），这种方式一般用作备选方案。 <img src="'+p+'" alt="alt text"></li></ul><h2 id="服务端驱动型内容协商机制" tabindex="-1">服务端驱动型内容协商机制 <a class="header-anchor" href="#服务端驱动型内容协商机制" aria-label="Permalink to &quot;服务端驱动型内容协商机制&quot;">​</a></h2><p>在服务端驱动型内容协商或者主动内容协商中，浏览器（或者其他任何类型的用户代理）会随同 URL 发送一系列的 HTTP 标头。这些标头描述了用户倾向的选择。服务器则以此为线索，通过内部算法来选择最佳方案提供给客户端。如果它不能提供一个合适的资源，它可能使用 406（Not Acceptable）、415（Unsupported Media Type）进行响应并为其支持的媒体类型设置标头（例如，分别对 POST 和 PATCH 请求使用 Accept-Post 或 Accept-Patch 标头 <img src="'+c+`" alt="alt text"> HTTP/1.1 规范指定了一系列的标准标头用于启动服务端驱动型内容协商（Accept、Accept-Charset、Accept-Encoding、Accept-Language）。尽管严格来说 User-Agent 并不在此列，有时候它还是会被用来确定给客户端发送的所请求资源的特定表示形式，不过这种做法不提倡使用。服务器会使用 Vary 标头来说明实际上哪些标头被用作内容协商的参考依据（确切来说是与之相关的响应标头），这样可以使缓存的运作更有效。</p><p>除此之外，有一个向可供选择的列表中增加更多标头的实验性提案，称为客户端提示（Client Hint）。客户端示意机制可以告知运行用户代理的设备类型（例如，是桌面计算机还是移动设备）。</p><p>即便服务端驱动型内容协商机制是最常用的对资源特定表示形式进行协商的方式，它也存在如下几个缺点：</p><ul><li>服务器对浏览器并非全知全能。即便是有了客户端示意扩展，也依然无法获取关于浏览器能力的全部信息。与客户端进行选择的代理驱动型内容协商机制不同，服务器端的选择总是显得有点武断。</li><li>客户端提供的信息相当冗长（HTTP/2 协议的标头压缩机制缓解了这个问题），并且存在隐私风险（HTTP 指纹识别技术）。</li><li>因为给定的资源需要返回不同的表示形式，共享缓存的效率会降低，而服务器端的实现会越来越复杂。</li></ul><h2 id="accept-标头" tabindex="-1">Accept 标头 <a class="header-anchor" href="#accept-标头" aria-label="Permalink to &quot;Accept 标头&quot;">​</a></h2><p>Accept 标头列举了用户代理希望接收的媒体资源的 MIME 类型。其中不同的 MIME 类型之间用逗号分隔，同时每一种 MIME 类型会配有一个品质因数（quality factor），该参数明确了不同 MIME 类型之间的相对优先级。</p><p>Accept 标头的值由浏览器或其他类型的用户代理确定，并且会由于上下文环境的不同而不同。比如在获取 HTML 页面、图片文件、视频文件或者是脚本文件的时候，无论是通过在地址栏中输入资源地址来获取还是通过 <code>&lt;img&gt;、&lt;video&gt; 或 &lt;audio&gt; </code>元素引用都是不一样的。浏览器可以自由使用它们认为最为合适的标头值；这里有一份常见浏览器 Accept 标头默认值的完整列表。</p><h2 id="accept-encoding-标头" tabindex="-1">Accept-Encoding 标头 <a class="header-anchor" href="#accept-encoding-标头" aria-label="Permalink to &quot;Accept-Encoding 标头&quot;">​</a></h2><p>Accept-Encoding 标头明确说明了（接收端）可以接受的内容编码形式（所支持的压缩算法）。该标头的值是一个 Q 因子清单（例如 br, gzip;q=0.8），用来提示不同编码类型值的优先级顺序。默认值 identity 的优先级最低（除非声明为其他优先级）。</p><p>将 HTTP 消息进行压缩是一种最重要的提升 Web 站点性能的方法。该方法会减小所要传输的数据量的大小，节省可用带宽。浏览器总是会发送该标头，服务器则应该配置为接受它，并且采用一定的压缩方案。</p><h2 id="accept-language" tabindex="-1">Accept-Language <a class="header-anchor" href="#accept-language" aria-label="Permalink to &quot;Accept-Language&quot;">​</a></h2><p>Accept-Language 标头用来提示用户期望获得的自然语言的优先顺序。该标头的值是一个 Q 因子清单（例如 de, en;q=0.7）。用户代理的图形界面上所采用的语言通常可以用来设置为默认值，但是大多数浏览器允许设置不同优先级的语言选项。</p><p>由于基于配置信息的信息熵的增加，修改后的值可以用作识别用户的指纹，所以不建议对其进行修改，不过这样的话 Web 站点也就不能依赖该值来揭示用户的真实期望。站点设计者不能过度热衷于通过这个标头来进行语言检测，因为它可能会导致糟糕的用户体验：</p><ul><li>站点设计者应该总是提供一种方式来使用户能够覆盖由服务器端选择的语言，例如在页面上提供一个用于语言选择的按钮。大多数用户代理会为 Accept-Language 标头提供一个默认值，该值采用的是用户界面的显示的语言。通常终端用户不能对其进行修改，或者是不知道该怎么修改，或者在他们计算机的环境中无法进行修改。</li><li>一旦用户覆盖了服务器端选择的语言选项，站点就不应该再使用语言检测技术，而应该忠于明确选择的语言选项。换句话说，只有站点的入口页面应该使用这个标头来选择合适的语言。</li></ul><h2 id="user-agent-标头" tabindex="-1">User-Agent 标头 <a class="header-anchor" href="#user-agent-标头" aria-label="Permalink to &quot;User-Agent 标头&quot;">​</a></h2><p>User-Agent 标头可以用来识别发送请求的浏览器。该字符串中包含有用空格间隔的产品标记符及注释的清单。</p><p>产品标记符由产品名称、后面紧跟的“/”以及产品版本号构成，例如 Firefox/4.0.1。用户代理可以随意添加多少产品标记符都可以。注释是一个用括号分隔的自由形式的字符串。显然括号本身不能用在该字符串中。规范没有规定注释的内部格式，不过一些浏览器会把一些标记符放置在里面，不同的标记符之间使用“;”分隔。</p><h2 id="accept-ch-标头" tabindex="-1">Accept-CH 标头 <a class="header-anchor" href="#accept-ch-标头" aria-label="Permalink to &quot;Accept-CH 标头&quot;">​</a></h2><p>客户端提示是一组 HTTP 请求标头字段，服务器可以主动地用它来获取关于设备、网络、用户以及用户代理指定的首选项的信息。然后，服务器可以根据客户端选择提供的信息来确定发送哪些资源。</p><p>服务器必须宣称它支持客户端提示，使用 Accept-CH 标头去表明它乐意去接收提示。当支持客户端提示的客户端接收到 Accept-CH 标头时，它可以选择在它的后续请求中附加部分或者列出的全部客户端提示标头。</p><p>例如，在以下发出带有 Accept-CH 标头的响应之后，客户端提示可能会在所有后续的请求中附加 Width、Downlink 和 Sec-CH-UA 标头。</p><div class="language-http vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Accept-CH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Width, Downlink, Sec-CH-UA</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 或者 HTML 中使用带有 http-equiv 属性的 &lt;meta&gt; 元素指定客户端提示。</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">meta</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> http-equiv</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Accept-CH&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> content</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Width, Downlink, Sec-CH-UA&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><table tabindex="0"><thead><tr><th>值</th><th>含义</th></tr></thead><tbody><tr><td>Device-Memory</td><td>标明客户端设备的内存大小。该值是个估计值，设备的实际内存值会向 2 的次方取整，且除以 1024。比如 512MB 的内存对应的值为 0.5。</td></tr><tr><td>Viewport-Width</td><td>标明用 CSS 像素数值表示的布局视口（layout viewport）宽度。</td></tr><tr><td>Width</td><td>标明用物理像素值表示的资源宽度（换句话说就是一张图片的固有大小）。</td></tr></tbody></table><p>用户代理（UA）标头允许服务器允许服务器基于用户代理（浏览器）、操作系统以及设备去改变响应。标头包括：Sec-CH-UA、Sec-CH-UA-Arch、Sec-CH-UA-Bitness、Sec-CH-UA-Full-Version-List、Sec-CH-UA-Full-Version、Sec-CH-UA-Mobile、Sec-CH-UA-Model、Sec-CH-UA-Platform 和 Sec-CH-UA-Platform-Version。</p><p>用户首选项媒体特性客户端提示允许服务器基于用户代理对 CSS 媒体特性（例如配色方案或者减少动态效果）的首选项来改变响应。标头包括：Sec-CH-Prefers-Reduced-Motion、Sec-CH-Prefers-Color-Scheme。</p><p>设备客户端提示允许服务器基于设备型号（包括可用内存和屏幕属性）来改变响应。标头包括：Device-Memory、DPR、Width、Viewport-Width。</p><p>网络客户端提示允许服务器基于用户的选择、网络带宽和传输延迟来改变响应。标头包括：Save-Data、Downlink、ECT、RTT。</p><h2 id="vary-响应标头" tabindex="-1">Vary 响应标头 <a class="header-anchor" href="#vary-响应标头" aria-label="Permalink to &quot;Vary 响应标头&quot;">​</a></h2><p>与前面列举的 Accept-* 形式的由客户端发送的标头相反，Vary 标头是由服务器在响应中发送的。<code>Vary 标头清单告诉客户端这些清单都是变量：服务器对不同清单将返回不同的内容</code>它指示了服务器在服务端驱动型内容协商阶段所使用的标头清单。Vary 标头是必要的，它用于将决策的规范告知缓存，这样它就可以进行复现。这将使缓存发挥它的作用，同时确保缓存可以向用户提供正确的内容。</p><p>特殊值“*”意味着在服务端驱动型内容协商过程中同时采纳了未在标头中传递的信息来选择合适的内容。</p><p>Vary 标头是在 HTTP 协议的 1.1 版本中新添加的，它是为了使缓存恰当地工作。缓存为了能够与服务端驱动型内容协商机制协同工作，需要知道服务器选择传送内容的规范。这样的话，缓存服务器就可以重复该算法，直接提供恰当的内容，而不需要向服务器发送更多的请求。显然，通配符“*”阻碍了缓存机制发挥作用，因为缓存并不知道该通配符究竟指代哪些元素</p><h2 id="代理驱动型内容协商机制" tabindex="-1">代理驱动型内容协商机制 <a class="header-anchor" href="#代理驱动型内容协商机制" aria-label="Permalink to &quot;代理驱动型内容协商机制&quot;">​</a></h2><p>服务端驱动型内容协商也有一些缺点：它不能很好的扩展。在协商机制中，每一个特性需要对应一个标头。如果想要使用屏幕大小、分辨率或者其他方面的特性，就需要创建一个新的 HTTP 标头。而且在每一次请求中都必须发送这些标头。在标头很少的时候，这并不是问题，但是随着数量的增多，消息的体积会导致性能的下降。带有精确信息的标头发送的越多，信息熵就会越大，也就准许了更多 HTTP 指纹识别行为，以及与此相关的隐私问题的发生。</p><p>从 HTTP 协议制定之初，该协议就准许另外一种协商机制：代理驱动型内容协商，或称为响应式协商。在这种协商机制中，当面临不明确的请求时，服务器会返回一个页面，其中包含了可供选择的资源的链接。资源呈现给用户，由用户做出选择。 <img src="`+n+'" alt="alt text"> 不幸的是，HTTP 标准没有明确指定提供可选资源链接的页面的格式，这阻碍了该过程的无痛自动化。除了退回至服务端驱动型内容协商外，这种自动化方法几乎无一例外都是通过脚本技术来完成的，尤其是 JavaScript 重定向技术：在检测了协商的条件之后，脚本会触发重定向动作。另外一个问题是，为了获得实际的资源，需要额外发送一次请求，减慢了将资源呈现给用户的速度。</p>',39)]))}const m=e(l,[["render",r]]);export{A as __pageData,m as default};
